DROP TABLE IF EXISTS "data";
CREATE TABLE "public"."data" (
    "_id" character(40) NOT NULL,
    "pid" character(40) NOT NULL,
    "sid" integer NOT NULL,
    "ref" character varying(100) NOT NULL,
    "js" jsonb NOT NULL,
    "embedding" vector(3072),
    CONSTRAINT "data_pkey" PRIMARY KEY ("_id")
)
WITH (oids = false);

CREATE INDEX idx_data_ref ON public.data USING btree (ref);

CREATE INDEX idx_data_sid ON public.data USING btree (sid);


